const fs = require('fs');
const path = require('path');
const checks = { folders_ok: true, folder_errors: [] };
const expectedFolders = ['registries', 'schemas', 'n8n', 'validators', 'skills', 'rules', 'docs'];
for (const folder of expectedFolders) {
  const folderPath = path.join(process.cwd(), folder);
  if (!fs.existsSync(folderPath)) {
    checks.folders_ok = false;
    checks.folder_errors.push({ folder, path: folderPath, exists: false });
  }
}
return [{ json: { ...$json, folder_validation: checks, had_folder_error: !checks.folders_ok } }];

const fs = require('fs');
const path = require('path');
const checks = { ollama_reachable: false, ollama_endpoint: 'http://localhost:11434', error: null };
const ollamaDir = path.join(process.env.USERPROFILE || process.env.HOME || '', '.ollama');
if (fs.existsSync(ollamaDir)) {
  checks.ollama_detected = true;
  checks.ollama_dir = ollamaDir;
  checks.ollama_reachable = true;
} else {
  checks.ollama_detected = false;
  checks.error = 'Ollama not found. Please install from https://ollama.ai';
}
return [{ json: { ...$json, ollama_validation: checks, had_ollama_error: !checks.ollama_reachable } }];

const folderCheck = $json.folder_validation?.folders_ok || false;
const ollamaCheck = $json.ollama_validation?.ollama_reachable || false;
const runtimeHealthy = folderCheck && ollamaCheck;
const packet = {
  instance_id: 'WF-000-' + Date.now(),
  artifact_family: 'runtime_health_report',
  schema_version: '1.0.0',
  producer_workflow: 'WF-000',
  dossier_ref: 'SYSTEM',
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    health_status: runtimeHealthy ? 'HEALTHY' : 'UNHEALTHY',
    folder_validation_ok: folderCheck,
    ollama_available: ollamaCheck,
    folder_errors: $json.folder_validation?.folder_errors || [],
    ollama_error: $json.ollama_validation?.error || null,
    recommendations: []
  }
};
if (!folderCheck) packet.payload.recommendations.push('Please ensure all required folders exist: registries, schemas, n8n, validators, skills, rules, docs');
if (!ollamaCheck) packet.payload.recommendations.push('Please install Ollama from https://ollama.ai and ensure it is running on localhost:11434');
return [{ json: { ...$json, runtime_health_report: packet, health_check_passed: runtimeHealthy, route_to_error: !runtimeHealthy } }];
